// Extract form fields + pass binary PDF through for Mistral OCR node
const item = $input.first();
const candidateName = item.json['Full Name'] || '';
const candidateEmail = item.json['Email'] || '';
const candidatePhone = item.json['Phone'] || '';
const jobRole = item.json['Job Role Applied'] || 'AI Automation Engineer';

// Pass binary key name so the OCR node can find the file
const binaryKeys = Object.keys(item.binary || {});
const binaryKey = binaryKeys[0] || 'CV (PDF)';

return [{
  json: {
    candidateName,
    candidateEmail,
    candidatePhone,
    jobRole
  },
  binary: item.binary
}];

const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});
const binaryKey = binaryKeys[0] || 'CV (PDF)';
const binaryData = item.binary[binaryKey];

if (!binaryData) {
  throw new Error('No binary PDF found in input. Check the form upload field name.');
}

// binaryMode:'separate' stores files on disk — binaryData.data is a filesystem
// reference, not base64. getBinaryDataBuffer() fetches the actual bytes.
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const pdfBase64 = buffer.toString('base64');

return [{
  json: {
    ...item.json,
    pdfBase64,
    pdfMimeType: binaryData.mimeType || 'application/pdf'
  }
}];

let data;
try {
  data = JSON.parse(input);
} catch (error) {
  return JSON.stringify({ valid: false, issues: ['Input is not valid JSON: ' + error.message] });
}

const maxScores = {
  skills: 30,
  industry: 20,
  experience: 15,
  education: 10,
  projects: 15,
  portfolio: 10,
};
const issues = [];
const normalized_scores = {};

for (const [key, max] of Object.entries(maxScores)) {
  const raw = data.scores && data.scores[key] !== undefined ? data.scores[key] : data['score_' + key];
  let value = Number(raw);
  if (!Number.isFinite(value)) {
    issues.push(key + ' score is missing or not numeric; using 0');
    value = 0;
  }
  if (value < 0 || value > max) {
    issues.push(key + ' score ' + value + ' is outside 0-' + max + '; clamp needed');
  }
  normalized_scores[key] = Math.min(max, Math.max(0, value));
}

const calculated_total = Object.values(normalized_scores).reduce((sum, value) => sum + value, 0);
const expected_decision = calculated_total >= 75 ? 'Shortlist' : calculated_total >= 50 ? 'Moderate' : 'Reject';

if (Number(data.total_score) !== calculated_total) {
  issues.push('total_score should equal ' + calculated_total + ', not ' + data.total_score);
}
if (data.decision && data.decision !== expected_decision) {
  issues.push('decision should be ' + expected_decision + ' for total_score ' + calculated_total);
}

return JSON.stringify({
  valid: issues.length === 0,
  issues,
  normalized_scores,
  calculated_total,
  expected_decision,
  qualificationRate: Number((calculated_total / 100).toFixed(2)),
});

