const item = $input.first();
const codeFence = '```';

function parseAgentOutput(value) {
  if (value && typeof value === 'object') return value;
  if (typeof value !== 'string') return {};

  let text = value.trim();
  if (text.startsWith(codeFence)) {
    text = text.replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
  }

  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    text = text.slice(firstBrace, lastBrace + 1);
  }

  try {
    return JSON.parse(text);
  } catch (error) {
    return { explanation: 'Agent output could not be parsed as JSON: ' + error.message };
  }
}

const rawEvaluation = item.json.output !== undefined ? item.json.output : item.json;
const evaluation = parseAgentOutput(rawEvaluation);
const formItems = $items('Extract Form Data');
const ocrItems = $items('Mistral OCR');
const form = formItems[0] ? formItems[0].json : {};
const ocr = ocrItems[0] ? ocrItems[0].json : {};
const pages = Array.isArray(ocr.pages) ? ocr.pages : [];
const cvText = pages.map((page) => page.markdown || page.extracted_text || '').join('\n\n').trim();

const maxScores = {
  skills: 30,
  industry: 20,
  experience: 15,
  education: 10,
  projects: 15,
  portfolio: 10,
};
const validationNotes = [];
const scores = {};

for (const [key, max] of Object.entries(maxScores)) {
  const rawScore = evaluation.scores && evaluation.scores[key] !== undefined ? evaluation.scores[key] : evaluation['score_' + key];
  let value = Number(rawScore);
  if (!Number.isFinite(value)) {
    validationNotes.push(key + ' score missing or not numeric; set to 0');
    value = 0;
  }
  if (value < 0 || value > max) {
    validationNotes.push(key + ' score ' + value + ' outside 0-' + max + '; clamped');
  }
  scores[key] = Math.min(max, Math.max(0, value));
}

if (cvText.length < 50) {
  validationNotes.push('OCR text is empty or too short; forced Reject with zero scores');
  for (const key of Object.keys(scores)) scores[key] = 0;
}

const totalScore = Object.values(scores).reduce((sum, value) => sum + value, 0);
const providedTotal = Number(evaluation.total_score);
if (Number.isFinite(providedTotal) && providedTotal !== totalScore) {
  validationNotes.push('Agent total_score ' + providedTotal + ' replaced with recalculated total ' + totalScore);
}

const decision = totalScore >= 75 ? 'Shortlist' : totalScore >= 50 ? 'Moderate' : 'Reject';
if (evaluation.decision && evaluation.decision !== decision) {
  validationNotes.push('Agent decision ' + evaluation.decision + ' replaced with threshold decision ' + decision);
}

const strengths = Array.isArray(evaluation.key_strengths) ? evaluation.key_strengths : [];
const gaps = Array.isArray(evaluation.key_gaps) ? evaluation.key_gaps : [];
const baseExplanation = String(evaluation.explanation || 'Candidate evaluated against the AI Automation Engineer rubric.').trim();
const validationSummary = validationNotes.length ? ' Validation notes: ' + validationNotes.join('; ') + '.' : '';

return [{
  json: {
    workflow_version: 'v2-auditable-agentic',
    screening_id: 'HR-' + Date.now(),
    timestamp: new Date().toISOString(),
    candidate_name: form.candidateName || '',
    candidate_email: form.candidateEmail || '',
    phone: form.candidatePhone || '',
    job_role: form.jobRole || 'AI Automation Engineer',
    score_skills: scores.skills,
    score_industry: scores.industry,
    score_experience: scores.experience,
    score_education: scores.education,
    score_projects: scores.projects,
    score_portfolio: scores.portfolio,
    total_score: totalScore,
    qualification_rate: Number((totalScore / 100).toFixed(2)),
    decision,
    explanation: baseExplanation + validationSummary,
    strengths: strengths.join('; '),
    gaps: gaps.join('; '),
    validation_notes: validationNotes.join('; ') || 'passed',
    ocr_pages: pages.length,
    cv_text_length: cvText.length,
    agent_raw_output: rawEvaluation,
  },
}];

